import { CheckCircleOutlined, CloseCircleOutlined, PlusOutlined } from '@ant-design/icons';
import { Button, message, Divider, Space, Breadcrumb, Tooltip, Tag } from 'antd';
import React, { useState, useRef, Fragment, useMemo, useCallback } from 'react';
import { PageContainer, FooterToolbar } from '@ant-design/pro-layout';
import type { ProColumns, ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { getControlRoles, deleteControlRole, enableControlRole } from '@/services/api';
import type { API } from '@/services/typings';
import { t, getTablePaginationConfig } from '../../global';
import NewOrUpdateForm, {
  FeatureList,
  FeatureLabels,
  PermissionState,
  getFeatureState,
  decodeControlRole,
} from './NewOrUpdateForm';
import { ControlPermissions_Permission } from "@/proto/rendezvous";
import { getLocalSortState, handleSortStateChange } from '@/components/Others/table_sort';
import { Link, useModel } from '@umijs/max';
import { hasAnyPermAssignControlRoleToUser, hasPermControlRolesEdit, hasPermToViewUsersInGroup } from '../RoleList/permissionUtils';
import MyModalConfirm from '@/components/Others/MyModalConfirm';
import UsersModal from './UsersModal';

export const CONTROL_ROLE_LIST_SORT_STATE_KEY = 'control_role_list_sort_state';


const NOT_LOGGED_CONTROL_ROLE_NAME = 'Not Logged';
const DEFAULT_CONTROL_ROLE_NAME = 'Default';
export const isPreservedControlRole = (name: string): boolean => {
  return [NOT_LOGGED_CONTROL_ROLE_NAME, DEFAULT_CONTROL_ROLE_NAME].includes(name);
};

const handleDelete = async (rows: API.ControlRoleListItem[]) => {
  const hide = message.loading(t('Deleting'));
  try {
    await deleteControlRole({
      data: {
        guids: rows.map((x) => x.guid),
      },
    });
    hide();
    message.success('Deletion is successful');
    return true;
  } catch (error) {
    hide();
    message.error(
      typeof error == 'string' ? (error as string) : 'Deletion failed, please try again!',
    );
    return false;
  }
};

const handleEnableDisable = async (rows: API.ControlRoleListItem[], disable: boolean) => {
  const hide = message.loading(disable ? t('Disabling') : t('Enabling'));
  try {
    await enableControlRole({
      data: {
        guids: rows.map((x) => x.guid),
        disable: disable,
      },
    });
    hide();
    message.success(disable ? 'Disabled successfully' : 'Enabled successfully');
    return true;
  } catch (error) {
    hide();
    message.error(
      typeof error == 'string' ? (error as string) : 'Operation failed, please try again!',
    );
    return false;
  }
};

/**
 * Status Tag Component
 */
const StatusTag = React.memo<{ status: number }>(({ status }) => {
  return (
    status === 1 ? <CheckCircleOutlined style={{ color: '#52c41a' }} /> : <CloseCircleOutlined style={{ color: '#f5222d' }} />
  );
});
StatusTag.displayName = 'StatusTag';

/**
 * Permissions Tags Component - shows enabled (green) and disabled (red) permissions
 * NOT_SET permissions are not displayed
 */
const PermissionsTags = React.memo<{ info: any }>(({ info }) => {
  const permissions = decodeControlRole(info);

  const enabled: ControlPermissions_Permission[] = [];
  const disabled: ControlPermissions_Permission[] = [];

  FeatureList.forEach((feature) => {
    const state = getFeatureState(permissions, feature);
    if (state === PermissionState.ENABLE) {
      enabled.push(feature);
    } else if (state === PermissionState.DISABLE) {
      disabled.push(feature);
    }
  });

  if (enabled.length === 0 && disabled.length === 0) {
    return <span style={{ color: '#999' }}>-</span>;
  }

  return (
    <Space size={[4, 4]} wrap>
      {enabled.map((feature) => (
        <Tag key={feature}>✓ {t(FeatureLabels[feature], true)}</Tag>
      ))}
      {disabled.map((feature) => (
        <Tag key={feature} style={{ opacity: 0.7 }}>✗ {t(FeatureLabels[feature], true)}</Tag>
      ))}
    </Space>
  );
});
PermissionsTags.displayName = 'PermissionsTags';

const TableList: React.FC = () => {
  const [createModalVisible, handleCreateModalVisible] = useState<boolean>(false);
  const [editModalVisible, handleEditModalVisible] = useState<boolean>(false);
  const [usersModalVisible, setUsersModalVisible] = useState<boolean>(false);
  const [usersModalItem, setUsersModalItem] = useState<API.ControlRoleListItem>();

  const actionRef = useRef<ActionType>();
  const [currentRow, setCurrentRow] = useState<API.ControlRoleListItem>();
  const [selectedRowsState, setSelectedRows] = useState<API.ControlRoleListItem[]>([]);
  const [sortState, setSortState] = useState<API.SortState>(() => getLocalSortState(CONTROL_ROLE_LIST_SORT_STATE_KEY));
  const { initialState } = useModel('@@initialState');
  const canEdit = hasPermControlRolesEdit(initialState?.user);
  const canViewUsers = hasPermToViewUsersInGroup(initialState?.user);
  const hasAnyPermAssignToUser = hasAnyPermAssignControlRoleToUser(initialState?.user);

  // Memoize delete handler
  const handleDeleteClick = useCallback(async (record: API.ControlRoleListItem) => {
    setCurrentRow(record);
    await handleDelete([record]);
    actionRef.current?.reloadAndRest?.();
  }, []);

  const handleBatchDeleteClick = useCallback(async () => {
    await handleDelete(selectedRowsState);
    setSelectedRows([]);
    actionRef.current?.reloadAndRest?.();
  }, [selectedRowsState]);

  const handleEditClick = useCallback((record: API.ControlRoleListItem) => {
    setCurrentRow(record);
    handleEditModalVisible(true);
  }, []);

  const handleEnableClick = useCallback(async (record: API.ControlRoleListItem) => {
    await handleEnableDisable([record], false);
    actionRef.current?.reload?.();
  }, []);

  const handleDisableClick = useCallback(async (record: API.ControlRoleListItem) => {
    await handleEnableDisable([record], true);
    actionRef.current?.reload?.();
  }, []);

  const handleBatchEnableClick = useCallback(async () => {
    await handleEnableDisable(selectedRowsState, false);
    setSelectedRows([]);
    actionRef.current?.reloadAndRest?.();
  }, [selectedRowsState]);

  const handleBatchDisableClick = useCallback(async () => {
    await handleEnableDisable(selectedRowsState, true);
    setSelectedRows([]);
    actionRef.current?.reloadAndRest?.();
  }, [selectedRowsState]);

  const DeleteComponent = React.memo<{ children: any; onClick: () => void }>(({ children, onClick }) => (
    <MyModalConfirm
      title={t('deleteConfirm', true, 'Are you sure to delete?')}
      onConfirm={onClick}
      okText="Yes"
      cancelText="No"
    >
      {children}
    </MyModalConfirm>
  ));
  DeleteComponent.displayName = 'DeleteComponent';


  // Memoize columns to prevent recreating on every render
  const columns: ProColumns<API.ControlRoleListItem>[] = useMemo(() => [
    {
      title: t('Name'),
      dataIndex: 'name',
      sorter: true,
      sortOrder: sortState.columnKey === 'name' ? sortState.order : undefined,
    },
    {
      title: t('Status', true),
      dataIndex: 'status',
      sorter: true,
      sortOrder: sortState.columnKey === 'status' ? sortState.order : undefined,
      width: 120,
      valueEnum: {
        0: { text: t('Disabled', true) },
        1: { text: t('Enabled', true) },
      },
      render: (_, record) => <StatusTag status={record.status} />,
    },
    {
      title: t('Permissions', true),
      dataIndex: 'info',
      search: false,
      render: (_, record) => <PermissionsTags info={record.info} />,
    },
    {
      title: `#${t('Users', true)}`,
      dataIndex: 'user_count',
      search: false,
      width: 120,
      render: (_, record) => {
        const count = record.user_count || 0;
        if (canViewUsers && !isPreservedControlRole(record.name)) {
          return (
            <Tooltip title={t('Click to view users', true)}>
              <Link to={`/roles/control/${record.guid}/users`} style={{ padding: '8px 12px', margin: '-8px -12px' }}>{count}</Link>
            </Tooltip>
          );
        }
        return count;
      },
    },
    {
      title: t('Note'),
      dataIndex: 'note',
      search: false,
      render: (_, record) => {
        if (record.name === NOT_LOGGED_CONTROL_ROLE_NAME) {
          return t('not_logged_control_role_description', true);
        }
        if (record.name === DEFAULT_CONTROL_ROLE_NAME) {
          return t('default_control_role_description', true);
        }
        return record.note;
      },
    },
    {
      title: t('Action'),
      search: false,
      width: 350,
      render: (text, record) => {
        const isPreserved = isPreservedControlRole(record.name);
        const actions: React.ReactNode[] = [];

        // For preserved roles, only permissions can be edited (not name/note)
        if (canEdit) {
          actions.push(
            <a key="edit" onClick={() => handleEditClick(record)}>
              {t('Edit')}
            </a>
          );
        }

        if (hasAnyPermAssignToUser && !isPreserved) {
          actions.push(
            <a key="users" onClick={() => { setUsersModalItem(record); setUsersModalVisible(true); }}>
              {t('Assign Users')}
            </a>
          );
        }

        if (canEdit) {
          actions.push(
            record.status === 1 ? (
              <a key="toggle" style={{ color: '#f5222d' }} onClick={() => handleDisableClick(record)}>{t('Disable', true)}</a>
            ) : (
              <a key="toggle" onClick={() => handleEnableClick(record)}>{t('Enable', true)}</a>
            )
          );
        }

        if (canEdit && !isPreserved) {
          actions.push(
            <DeleteComponent key="delete" onClick={() => handleDeleteClick(record)}>
              <a style={{ color: '#f5222d' }}>{t('Delete')}</a>
            </DeleteComponent>
          );
        }

        return actions.length > 0 ? (
          actions.reduce((prev, curr, index) => (
            <Fragment key={index}>
              {prev}
              <Divider type="vertical" />
              {curr}
            </Fragment>
          ))
        ) : null;
      },
    },
  ], [sortState, handleEditClick, handleDeleteClick, handleEnableClick, handleDisableClick, canEdit, canViewUsers]);

  return (
    <PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.list.role-list', true) },
          { title: t('menu.list.role-list.control', true) },
        ]} />
      )}
    >
      <ProTable<API.ControlRoleListItem, API.PageParams>
        headerTitle={t('Control Roles', true)}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'control_role_list_columns_state' }}
        actionRef={actionRef}
        rowKey="guid"
        search={{
          labelWidth: 120,
        }}
        toolBarRender={() => canEdit ? [
          <Button
            type="primary"
            key="primary"
            onClick={() => {
              handleCreateModalVisible(true);
            }}
          >
            <PlusOutlined /> {t('Create')}
          </Button>,
        ] : []}
        request={async (params) => {
          const res = await getControlRoles(params, undefined, undefined, sortState);
          return res;
        }}
        columns={columns}
        rowSelection={canEdit ? {
          onChange: (_, selectedRows) => {
            setSelectedRows(selectedRows);
          },
        } : undefined}
        pagination={getTablePaginationConfig("control_role_list")}
        onChange={(_, __, sorter) => {
          handleSortStateChange(sorter, actionRef, CONTROL_ROLE_LIST_SORT_STATE_KEY, setSortState);
        }}
      />
      {selectedRowsState?.length > 0 && (
        <FooterToolbar
          extra={
            <div>
              {t('Chosen')} <a style={{ fontWeight: 600 }}>{selectedRowsState.length}</a>{' '}
              {t('Items')}
            </div>
          }
        >
          <Space>
            <Button onClick={handleBatchEnableClick}>{t('Enable', true)}</Button>
            <Button style={{ color: '#f5222d', borderColor: '#f5222d' }} onClick={handleBatchDisableClick}>{t('Disable', true)}</Button>
            {selectedRowsState.every(x => !isPreservedControlRole(x.name)) && <DeleteComponent onClick={handleBatchDeleteClick}>
              <Button style={{ color: '#f5222d', borderColor: '#f5222d' }}>{t('Delete')}</Button>
            </DeleteComponent>}
          </Space>
        </FooterToolbar>
      )}
      {createModalVisible && (
        <NewOrUpdateForm
          isNew={true}
          visible={createModalVisible}
          onVisibleChange={handleCreateModalVisible}
          actionRef={actionRef}
          initialValues={undefined}
        />
      )}
      {editModalVisible && (
        <NewOrUpdateForm
          isNew={false}
          visible={editModalVisible}
          onVisibleChange={handleEditModalVisible}
          actionRef={actionRef}
          initialValues={currentRow || undefined}
          isPreserved={currentRow ? isPreservedControlRole(currentRow.name) : false}
        />
      )}
      {usersModalItem && usersModalVisible && (
        <UsersModal
          visible={usersModalVisible}
          setVisible={setUsersModalVisible}
          controlRoleGuid={usersModalItem.guid}
          controlRoleName={usersModalItem.name}
          closeChangedCallback={() => actionRef.current?.reload()}
        />
      )}
    </PageContainer>
  );
};

export default TableList;
