import { Steps, message, Button, Tabs, Spin, List, Select } from 'antd';
import React, { useRef, useState, useEffect } from 'react';
import type { ActionType } from '@ant-design/pro-table';
import type { ProFormInstance, SubmitterProps } from '@ant-design/pro-form';
import { ModalForm, ProFormText, ProFormTextArea } from '@ant-design/pro-form';
import { addControlRole, updateControlRole, getControlRole } from '@/services/api';
import type { API } from '@/services/typings';
import { t } from '../../global';
import {
  ControlPermissions,
  ControlPermissions_Permission,
} from "@/proto/rendezvous";

// Feature enum values matching protobuf definition
export const FeatureList: ControlPermissions_Permission[] = [
  ControlPermissions_Permission.keyboard,
  ControlPermissions_Permission.remote_printer,
  ControlPermissions_Permission.clipboard,
  ControlPermissions_Permission.file,
  ControlPermissions_Permission.audio,
  ControlPermissions_Permission.camera,
  ControlPermissions_Permission.terminal,
  ControlPermissions_Permission.tunnel,
  ControlPermissions_Permission.restart,
  ControlPermissions_Permission.recording,
  ControlPermissions_Permission.block_input,
  ControlPermissions_Permission.remote_modify,
];

export const FeatureLabels: Record<ControlPermissions_Permission, string> = {
  [ControlPermissions_Permission.keyboard]: 'Keyboard/Mouse',
  [ControlPermissions_Permission.remote_printer]: 'Remote Printer',
  [ControlPermissions_Permission.clipboard]: 'Clipboard',
  [ControlPermissions_Permission.file]: 'File Transfer',
  [ControlPermissions_Permission.audio]: 'Audio',
  [ControlPermissions_Permission.camera]: 'Camera',
  [ControlPermissions_Permission.terminal]: 'Terminal',
  [ControlPermissions_Permission.tunnel]: 'TCP Tunnel',
  [ControlPermissions_Permission.restart]: 'Remote Restart',
  [ControlPermissions_Permission.recording]: 'Recording Session',
  [ControlPermissions_Permission.block_input]: 'Block User Input',
  [ControlPermissions_Permission.remote_modify]: 'Remote Configuration Modification',
  [ControlPermissions_Permission.UNRECOGNIZED]: 'Unknown',
};

// Permission states (2 bits per permission)
export const PermissionState = {
  NOT_SET: 0,
  DISABLE: 1,
  ENABLE: 2,
  // 3 is invalid, treated as NOT_SET
} as const;

type PermissionStateType = typeof PermissionState[keyof typeof PermissionState];

// Helper functions for bitwise mask operations (matching proto_ext.rs)
// NOTE: Using number instead of bigint for browser compatibility (IE11, Safari <14).
// JavaScript bitwise operators work on 32-bit integers, so this supports up to 16 features (2 bits each).
// When features exceed 16, switch to bigint and update gen_proto.py to use forceLong=bigint.

// Get the state of a permission (2 bits per permission)
// Returns: 0 = not set, 1 = disable, 2 = enable (3 is invalid, treated as 0)
export const getFeatureState = (permissions: number, permission: ControlPermissions_Permission): PermissionStateType => {
  const index = permission as number;
  const bitOffset = index * 2;
  if (bitOffset < 0 || bitOffset >= 32) {
    return PermissionState.NOT_SET;
  }
  const state = (permissions >> bitOffset) & 0x3;
  // 3 is invalid, treat as NOT_SET
  if (state === 3) {
    return PermissionState.NOT_SET;
  }
  return state as PermissionStateType;
};

// Set the state of a permission (2 bits per permission)
const setFeatureState = (permissions: number, permission: ControlPermissions_Permission, state: PermissionStateType): number => {
  const index = permission as number;
  const bitOffset = index * 2;
  if (bitOffset < 0 || bitOffset >= 32) {
    return permissions;
  }
  // Clear the 2 bits for this permission
  const mask = ~(0x3 << bitOffset);
  const cleared = (permissions & mask) >>> 0;
  // Set the new state
  return (cleared | (state << bitOffset)) >>> 0;
};

// Helper functions for protobuf serialization
const encodeControlRole = (permissions: number): { proto: number[] } => {
  const data = ControlPermissions.create({ permissions: permissions });
  const encoded = ControlPermissions.encode(data).finish();
  return { proto: Array.from(encoded) };
};

export const decodeControlRole = (data: { proto: number[] } | any): number => {
  if (data && data.proto && Array.isArray(data.proto)) {
    const uint8Array = new Uint8Array(data.proto);
    const decoded = ControlPermissions.decode(uint8Array);
    return Number(decoded.permissions);
  }
  return 0;
};

const getFeatureTitle = (permission: ControlPermissions_Permission) => {
  return t(FeatureLabels[permission] || 'Unknown', true);
};

const getStateLabel = (state: PermissionStateType) => {
  switch (state) {
    case PermissionState.ENABLE:
      return t('control_role_enable', true);
    case PermissionState.DISABLE:
      return t('control_role_disable', true);
    default:
      return t('control_role_not_set', true);
  }
};

// Step enum for create flow
export enum ControlRoleStep {
  Overview = 0,
  Permissions = 1,
}

type FormStep = {
  formItems: React.ReactNode;
  submitterProps: SubmitterProps;
};

export interface NewOrUpdateFormProps {
  isNew: boolean;
  visible: boolean;
  onVisibleChange: (visible: boolean) => void;
  actionRef: React.MutableRefObject<ActionType | undefined>;
  initialValues?: API.ControlRoleListItem;
  isPreserved?: boolean;  // For preserved roles, only allow editing permissions
}

const NewOrUpdateForm: React.FC<NewOrUpdateFormProps> = (props) => {
  const { isNew, visible, onVisibleChange, actionRef, initialValues, isPreserved } = props;
  const formRef = useRef<ProFormInstance>();
  const [name, setName] = useState<string>(initialValues?.name ?? '');
  const [note, setNote] = useState<string>(initialValues?.note ?? '');
  const [permissions, setPermissions] = useState<number>(0);
  const [initialPermissions, setInitialPermissions] = useState<number>(0);
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<number>(ControlRoleStep.Overview);

  // Load existing permissions when editing
  useEffect(() => {
    if (!isNew && initialValues?.guid && visible) {
      setLoading(true);
      setName(initialValues?.name ?? '');
      setNote(initialValues?.note ?? '');
      // For preserved roles, start directly on Permissions tab
      if (isPreserved) {
        setStep(ControlRoleStep.Permissions);
      }
      getControlRole(initialValues.guid)
        .then((res: any) => {
          if (res?.info) {
            const decoded = decodeControlRole(res.info);
            setInitialPermissions(decoded);
            setPermissions(decoded);
          }
        })
        .catch(() => {
          // ignore
        })
        .finally(() => {
          setLoading(false);
        });
    } else if (isNew && visible) {
      // Reset state for new creation
      setName('');
      setNote('');
      setInitialPermissions(0);
      setPermissions(0);
      setStep(ControlRoleStep.Overview);
    }
  }, [isNew, initialValues?.guid, visible, isPreserved]);

  const handleSetPermissionState = (permission: ControlPermissions_Permission, state: PermissionStateType) => {
    setPermissions(setFeatureState(permissions, permission, state));
  };

  const stateOptions = [
    { value: PermissionState.NOT_SET, label: getStateLabel(PermissionState.NOT_SET) },
    { value: PermissionState.ENABLE, label: getStateLabel(PermissionState.ENABLE) },
    { value: PermissionState.DISABLE, label: getStateLabel(PermissionState.DISABLE) },
  ];

  // Get label color based on permission state
  const getLabelColor = (state: PermissionStateType): string | undefined => {
    switch (state) {
      case PermissionState.ENABLE:
        return '#52c41a';
      case PermissionState.DISABLE:
        return '#ff4d4f';
      default:
        return undefined;
    }
  };

  if (!visible) return null;

  const leaveOnlySubmittable = (_: any, dom: JSX.Element[]) => dom.pop();

  // Step 1: Basic Info
  const basicInfoTitle = t('Overview', true);
  const basicInfoFormItems = (
    <>
      <ProFormText
        name="name"
        label={t('Name', true)}
        initialValue={name}
        rules={[
          { required: true },
          { min: 4, max: 300 },
        ]}
        placeholder={t('Name', true) as string}
        fieldProps={{
          onChange: (evt) => setName(evt.target.value)
        }}
      />
      <ProFormTextArea
        name="note"
        label={t('Note', true)}
        initialValue={note}
        rules={[{ max: 300 }]}
        placeholder={t('Optional note', true) as string}
        fieldProps={{
          rows: 3,
          onChange: (evt) => setNote(evt.target.value)
        }}
      />
    </>
  );
  const basicInfoSubmitterRender = {
    searchConfig: { submitText: t(isNew ? 'Continue' : 'Save', true) },
    submitButtonProps: {
      disabled: name.length < 4,
      loading: loading,
    },
    render: leaveOnlySubmittable,
  };

  // Step 2: Permissions
  const permissionsTitle = t('Permissions', true);
  const permissionsFormItems = (
    <List
      split={false}
      dataSource={FeatureList}
      renderItem={(permission) => {
        const state = getFeatureState(permissions, permission);
        const isEnabled = state === PermissionState.ENABLE;
        const isDisabled = state === PermissionState.DISABLE;
        const prefix = isEnabled ? '✓' : isDisabled ? '✗' : '';
        const labelStyle: React.CSSProperties = {
          fontSize: 14,
          flex: 1,
          opacity: isDisabled ? 0.7 : 1,
        };
        return (
          <List.Item style={{ padding: '8px 0' }}>
            <div style={{ display: 'flex', alignItems: 'center', width: '100%' }}>
              <span style={{ width: 20, opacity: isDisabled ? 0.7 : 1 }}>{prefix}</span>
              <span style={labelStyle}>{getFeatureTitle(permission)}</span>
              <Select
                value={state}
                onChange={(value) => handleSetPermissionState(permission, value)}
                options={stateOptions}
                style={{ width: 200 }}
              />
            </div>
          </List.Item>
        );
      }}
    />
  );
  const permissionsSubmitterRender = {
    searchConfig: { submitText: t(isNew ? 'Create' : 'Save', true) },
    submitButtonProps: {
      loading: loading,
    },
    render: isNew ? (_: any, dom: JSX.Element[]) => {
      const submitButton = dom.pop();
      return [
        <div key="wrapper" style={{ display: 'flex', width: '100%', justifyContent: 'flex-end', gap: '8px' }}>
          <Button onClick={() => setStep(ControlRoleStep.Overview)}>
            {t('Back', true)}
          </Button>
          {submitButton}
        </div>
      ];
    } : leaveOnlySubmittable,
  };

  // Step items for Steps component
  const stepItems = [
    { title: basicInfoTitle },
    { title: permissionsTitle }
  ];

  // Form steps configuration
  const formSteps: FormStep[] = [
    {
      formItems: basicInfoFormItems,
      submitterProps: basicInfoSubmitterRender,
    },
    {
      formItems: permissionsFormItems,
      submitterProps: permissionsSubmitterRender,
    },
  ];

  // Handle tab change for edit mode
  const handleTabChange = (activeKey: string) => {
    setStep(parseInt(activeKey));
  };

  // onFinish handler for create flow
  const onFinishCreate = async () => {
    switch (step) {
      case ControlRoleStep.Overview:
        setStep(ControlRoleStep.Permissions);
        return false;
      case ControlRoleStep.Permissions:
        setLoading(true);
        const hide = message.loading(t('Creating'));
        try {
          await addControlRole({
            data: {
              name,
              note: note || null,
              info: encodeControlRole(permissions),
            }
          });
          hide();
          message.success(t('Created successfully'));
          actionRef.current?.reload();
          onVisibleChange(false);
          return true;
        } catch (error) {
          hide();
          message.error(
            typeof error == 'string' ? error : t('Creation failed, please try again!')
          );
          return false;
        } finally {
          setLoading(false);
        }
      default:
        return false;
    }
  };

  // onFinish handler for update flow
  const onFinishUpdate = async () => {
    setLoading(true);
    const hide = message.loading(t('Updating'));
    try {
      const data: {
        name?: string;
        note?: string;
        info?: { proto: number[] };
      } = {};

      if (name !== (initialValues?.name ?? '')) {
        data.name = name;
      }
      if (note !== (initialValues?.note ?? '')) {
        data.note = note;
      }
      if (permissions !== initialPermissions) {
        data.info = encodeControlRole(permissions);
      }

      // Skip update if nothing changed
      if (Object.keys(data).length === 0) {
        hide();
        onVisibleChange(false);
        return true;
      }

      await updateControlRole(initialValues!.guid, { data });
      hide();
      message.success(t('Update successfully'));
      actionRef.current?.reload();
      onVisibleChange(false);
      return true;
    } catch (error) {
      hide();
      message.error(
        typeof error == 'string' ? error : t('Update failed, please try again!')
      );
      return false;
    } finally {
      setLoading(false);
    }
  };

  const onFinish = async () => isNew ? await onFinishCreate() : await onFinishUpdate();

  return (
    <ModalForm
      formRef={formRef}
      title={t(isNew ? 'Create' : 'Edit', true)}
      open={visible}
      width={650}
      onOpenChange={onVisibleChange}
      submitter={formSteps[step].submitterProps}
      modalProps={{
        maskClosable: false,
        destroyOnClose: true,
      }}
      onFinish={onFinish}
    >
      <Spin spinning={loading}>
        {isNew ? (
          <Steps
            current={step}
            size="small"
            labelPlacement="vertical"
            items={stepItems}
            style={{ marginBottom: 24 }}
          />
        ) : isPreserved ? (
          // For preserved roles, don't show tabs
          null
        ) : (
          <Tabs
            activeKey={step.toString()}
            onChange={handleTabChange}
            style={{ marginBottom: 0 }}
            items={[
              { key: ControlRoleStep.Overview.toString(), label: t('Overview', true) },
              { key: ControlRoleStep.Permissions.toString(), label: t('Permissions', true) },
            ]}
          />
        )}

        <div style={{
          padding: '0 18px',
          maxHeight: 'calc(80vh - 200px)',
          overflowY: 'auto',
          overflowX: 'hidden'
        }}>
          {formSteps[step].formItems}
        </div>
      </Spin>
    </ModalForm>
  );
};

export default NewOrUpdateForm;
