import { users, assignUsersToControlRole, removeUsersFromControlRole } from "@/services/api"
import { Button, Col, message, Modal, Row, Typography } from "antd"
import { useEffect, useRef, useState } from "react"
import { API } from '@/services/typings';
import ProTable, { ActionType } from "@ant-design/pro-table";
import { getTablePaginationConfig, t } from "@/global";
import { CloseOutlined } from "@ant-design/icons";
import { useModel } from "@umijs/max";
import { getLocalSortState, handleSortStateChange } from "@/components/Others/table_sort";
import { USER_LIST_SORT_STATE_KEY, userColumns } from "../UserList";
import { canAssignControlRoleToUser, hasAnyPermAssignControlRoleToUser } from "../RoleList/permissionUtils";

type UsersModalProps = {
  visible: boolean
  setVisible: React.Dispatch<React.SetStateAction<boolean>>
  controlRoleGuid: string,
  controlRoleName: string,
  closeChangedCallback: () => void;
}

const UsersModal: React.FC<UsersModalProps> = (props) => {
  const [userList, setUserList] = useState<API.UserListItem[]>([]);
  const [selectedRowKeys, setSelectedRowKeys] = useState<string[]>([]);
  const [everChanged, setEverChanged] = useState<boolean>(false);
  const [sortState, setSortState] = useState<API.SortState>(() => getLocalSortState(USER_LIST_SORT_STATE_KEY));
  const actionRef = useRef<ActionType>();
  const { initialState } = useModel('@@initialState');
  const hasAnyPermAssignToUser = hasAnyPermAssignControlRoleToUser(initialState?.user);

  useEffect(() => {
    if (props.visible) {
      actionRef.current?.reload();
    }
  }, [props.visible]);

  const onSave = async () => {
    const toAdd = userList.filter((u) => u.control_role_name !== props.controlRoleName && selectedRowKeys.includes(u.guid));
    const toRemove = userList.filter((u) => u.control_role_name === props.controlRoleName && !selectedRowKeys.includes(u.guid));

    if (toAdd.length > 0) {
      try {
        await assignUsersToControlRole(props.controlRoleGuid, {
          data: { user_guids: toAdd.map(u => u.guid) }
        });
      } catch (e: any) {
        message.error(typeof e === 'string' ? e : 'Failed to add users');
        return;
      }
    }

    if (toRemove.length > 0) {
      try {
        await removeUsersFromControlRole({
          data: { user_guids: toRemove.map(u => u.guid) }
        });
      } catch (e: any) {
        message.error(typeof e === 'string' ? e : 'Failed to remove users');
        return;
      }
    }

    const changedCount = toAdd.length + toRemove.length;
    message.success(`${changedCount} record${changedCount === 1 ? " is" : "s are"} successfully changed`);
    setEverChanged(true);
    actionRef.current?.reload();
  }

  const onReset = async () => {
    actionRef.current?.reset?.();
  }

  const saveButtonEnabled = () => {
    const toAdd = userList.filter((u) => u.control_role_name !== props.controlRoleName && selectedRowKeys.includes(u.guid));
    const toRemove = userList.filter((u) => u.control_role_name === props.controlRoleName && !selectedRowKeys.includes(u.guid));
    return toAdd.length + toRemove.length > 0;
  }

  const onClose = () => {
    props.setVisible(false);
    setUserList([]);
    setSelectedRowKeys([]);
    if (everChanged) props.closeChangedCallback();
    setEverChanged(false);
  }

  const columns = userColumns({
    actionRef,
    myname: initialState?.user?.name,
    is_select: true,
    sortState,
    setSortState,
  });

  return <Modal
    open={props.visible}
    width="90vw"
    style={{ overflowX: "hidden" }}
    footer={saveButtonEnabled() ?
      <Row justify="center" gutter={16}>
        <Col>
          <Button onClick={onReset}>{t("Reset")}</Button>
        </Col>
        <Col>
          <Button onClick={onSave} type="primary">{t("Save")}</Button>
        </Col>
      </Row>
      : null}
    onCancel={onClose}
    destroyOnClose={true}
    title={<span>{t(hasAnyPermAssignToUser ? 'Assign Users' : 'View Users', true)} - <Typography.Text mark>{props.controlRoleName}</Typography.Text></span>}
    closeIcon={<CloseOutlined />}
  >
    <ProTable<API.UserListItem, API.PageParams>
      columnsState={{ persistenceType: 'localStorage', persistenceKey: 'control_role_users_modal_columns_state' }}
      rowKey={"guid"}
      actionRef={actionRef}
      search={{ filterType: 'light' }}
      defaultSize="middle"
      columns={columns as any}
      request={users}
      postData={(items: API.UserListItem[]) => {
        setUserList(items);
        setSelectedRowKeys(items.filter((u) => u.control_role_name === props.controlRoleName).map((u) => u.guid));
        return items;
      }}
      rowSelection={{
        selectedRowKeys: selectedRowKeys,
        onChange: hasAnyPermAssignToUser ? (keys) => {
          setSelectedRowKeys(keys as string[]);
        } : undefined,
        getCheckboxProps: (record) => ({
          disabled: !canAssignControlRoleToUser(initialState?.user, record),
        }),
      }}
      pagination={getTablePaginationConfig('control_role_users_modal')}
      style={{ paddingLeft: '5vw', paddingRight: '5vw' }}
      onChange={(_, __, sorter) => handleSortStateChange(sorter, actionRef, USER_LIST_SORT_STATE_KEY, setSortState)}
    />
  </Modal>
}

export default UsersModal;
